import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as o,f as a}from"./app-23c1c732.js";const r={},u=a('<p>​ 从弗洛伊德的&quot;俄狄浦斯&quot;到拉康的&quot;镜像&quot;理论,便是着眼于儿童时期,结构着人被符号化的过程,同时伴随着内心空缺感,以及向他者确证存在感的欲望等现象</p><h1 id="恋物癖-与过渡客体" tabindex="-1"><a class="header-anchor" href="#恋物癖-与过渡客体" aria-hidden="true">#</a> &quot;恋物癖&quot;与过渡客体</h1><p>​ &quot;恋物癖&quot;作为第一个现象,是一个很自然的例子,可以和婴儿视野中父母的缺失相联系,缺乏安全感,便会通过过渡客体来度过,例如小熊玩偶,一本书,一个玩具</p><h1 id="我是哪里来的-与欲望客体" tabindex="-1"><a class="header-anchor" href="#我是哪里来的-与欲望客体" aria-hidden="true">#</a> &quot;我是哪里来的&quot;与欲望客体</h1><p>​ 欲望不针对某个能够满足需求的客体，而是针对一个幻想的客体。相对地，客体在幻想中的功能就在于「填<br> 补主体在象征系统中所缺乏的东西」。而该机制的关键则在于儿童的语言学习,当一个孩子对物体撒手会掉落,磕碰到会痛,等种种现象疑惑,不解时,会对他意识带来混乱和癔症化的痛苦,但当他问出第一句&quot;我是哪里来的&quot;时,并不是要理解自己的出生,而是将不解暂时消解了,希望世界能够接纳自己,&quot;不要不带自己玩&quot;</p><h1 id="他者即地狱-与镜像理论" tabindex="-1"><a class="header-anchor" href="#他者即地狱-与镜像理论" aria-hidden="true">#</a> &quot;他者即地狱&quot;与镜像理论</h1>',6),c=[u];function h(_,d){return e(),o("div",null,c)}const s=t(r,[["render",h],["__file","结构主义小宝宝.html.vue"]]);export{s as default};
